const raw = $input.first().json.output ?? '';
let decision;
try {
  decision = JSON.parse(raw);
} catch (e) {
  decision = { tier: 'economy', model: 'gpt-4o-mini', refinedPrompt: String(raw), reason: 'fallback: agent did not return JSON' };
}
const body = $('Paid Endpoint (x402 target)').item.json.body || {};
return [{ json: { ...decision, topic: body.topic ?? null, runId: body.runId ?? $execution.id } }];

const j = $input.first().json;
const usage = j.usage || {};
const tokens = usage.total_tokens || 0;

// --- adjust these to your real numbers ---
const revenue = 0.04;            // price you charge per call (paid endpoint)
const tokenRatePer1k = 0.005;    // blended $/1k tokens, replace with real rate
const externalSpend = 0;         // sum of outbound x402 API spend this call
const feePct = 0.05;             // Alephant fee
// -----------------------------------------

const tokenCost = (tokens / 1000) * tokenRatePer1k;
const fee = revenue * feePct;
const netMargin = revenue - tokenCost - externalSpend - fee;
const marginPct = revenue > 0 ? (netMargin / revenue) * 100 : 0;

return [{ json: {
  result: j.text ?? j.output ?? j,
  model: j.model ?? null,
  runId: $('Parse Decision').item.json.runId,
  tokens,
  revenue,
  tokenCost: Number(tokenCost.toFixed(4)),
  externalSpend,
  fee: Number(fee.toFixed(4)),
  netMargin: Number(netMargin.toFixed(4)),
  marginPct: Number(marginPct.toFixed(1))
} }];
